import React, { useState } from "react";
import Dice from "react-dice-roll";

const boardImage = "/torahpoly_board.png";

const cardImages = [
  "/cards/1_bereshitA.png",
  "/cards/1B_bereshitB.png",
  "/cards/har_habayit_1a.png",
  "/cards/har_habayit_1b.png",
  "/cards/tzadik_card.png",
  "/cards/Sotah_47.png",
];

function App() {
  const [boardRotation, setBoardRotation] = useState(0); // degrees: 0,90,180,270
  const [playerPosition, setPlayerPosition] = useState(0);
  const [turnCount, setTurnCount] = useState(1);
  const [diceRolls, setDiceRolls] = useState([]);
  const [playerName, setPlayerName] = useState("");
  const [currentCardIndex, setCurrentCardIndex] = useState(0);

  const rotateBoard = () => {
    setBoardRotation((prev) => (prev + 90) % 360);
  };

  // When dice roll ends, collect values. When two dice rolled, sum and update position
  const handleDiceRoll = (value) => {
    setDiceRolls((prev) => {
      const newRolls = [...prev, value];
      if (newRolls.length === 2) {
        const total = newRolls[0] + newRolls[1];
        setPlayerPosition((pos) => (pos + total) % 40);
        setTurnCount((count) => count + 1);
        return [];
      }
      return newRolls;
    });
  };

  const prevCard = () => {
    setCurrentCardIndex((i) => (i - 1 + cardImages.length) % cardImages.length);
  };
  const nextCard = () => {
    setCurrentCardIndex((i) => (i + 1) % cardImages.length);
  };

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      <div style={{ marginBottom: 20 }}>
        <label>
          Enter Player Name:{" "}
          <input
            type="text"
            value={playerName}
            onChange={(e) => setPlayerName(e.target.value)}
            style={styles.input}
            placeholder="Your Name"
          />
        </label>
        {playerName && <p>Player: <strong>{playerName}</strong></p>}
      </div>

      <div style={{ marginBottom: 20 }}>
        <img
          src={boardImage}
          alt="Game Board"
          style={{
            width: 900, // increased width for better readability
            maxWidth: "95vw",
            border: "2px solid #333",
            transform: `rotate(${boardRotation}deg)`,
            transition: "transform 0.5s ease",
            borderRadius: 12,
          }}
        />
        <br />
        <button onClick={rotateBoard} style={styles.button}>
          Rotate Board 90°
        </button>
      </div>

      <div style={{ marginBottom: 30 }}>
        <h2>Roll Dice</h2>
        <div style={{ display: "flex", justifyContent: "center", gap: 20 }}>
          <Dice
            sides={6}
            onRoll={handleDiceRoll}
            faceColor="#007bff"
            dotColor="#fff"
            disabled={false}
            rollTime={1}
          />
          <Dice
            sides={6}
            onRoll={handleDiceRoll}
            faceColor="#007bff"
            dotColor="#fff"
            disabled={false}
            rollTime={1}
          />
        </div>
        <p>Turn: {turnCount}</p>
        <p>Player Position: {playerPosition}</p>
      </div>

      <div style={{ textAlign: "center" }}>
        <h2>Parsha Card Viewer</h2>
        <img
          src={cardImages[currentCardIndex]}
          alt="Parsha Card"
          style={styles.cardImage}
        />
        <div>
          <button onClick={prevCard} style={styles.button}>
            Previous
          </button>
          <button onClick={nextCard} style={{ ...styles.button, marginLeft: 10 }}>
            Next
          </button>
        </div>
        <p>
          Showing card {currentCardIndex + 1} of {cardImages.length}
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    padding: 20,
    backgroundColor: "#f0f2f5",
    minHeight: "100vh",
    textAlign: "center",
  },
  button: {
    backgroundColor: "#007bff",
    color: "white",
    border: "none",
    borderRadius: 8,
    padding: "10px 20px",
    fontSize: 16,
    cursor: "pointer",
  },
  input: {
    fontSize: 16,
    padding: "5px 10px",
    borderRadius: 4,
    border: "1px solid #ccc",
  },
  cardImage: {
    width: 300,
    borderRadius: 12,
    border: "2px solid #333",
    boxShadow: "0 4px 10px rgba(0,0,0,0.2)",
    marginBottom: 10,
  },
};

export default App;
